# OEIS sequence: A342933

from math import factorial
def A342933(n):
    c, j, f = 0, 1, factorial(n)
    while j <= n:
        k = n//j
        m = n//k
        c += f*(m*(m+1)*(2*m+1)-(j-1)*j*(2*j-1))//k
        j = m+1
    return c//6 # _Chai Wah Wu_, May 14 2026

